### 2. **Sync Fabric: Unified Transport Abstraction**

#### A. **Core Interface (`lib/sync-fabric.ts`)**

```ts
export type SyncEvent =
  | { type: 'PRESENCE'; payload: { userId: string; cursor?: Cursor } }
  | { type: 'STATE_DELTA'; payload: { projectId: string; delta: YjsPatch } }
  | { type: 'LOCK_ACQUIRED'; payload: { segmentId: string; userId: string } }
  | { type: 'SYNC_COMPLETE'; payload: { projectId: string; version: number } };

export interface SyncTransport {
  connect(projectId: string): void;
  disconnect(): void;
  send(event: SyncEvent): void;
  onEvent(handler: (event: SyncEvent) => void): () => void;
}
```

#### B. **Dual-Mode Transport Implementation**

```ts
// transports/SseWssFabric.ts
export class SseWssFabric implements SyncTransport {
  private projectId: string | null = null;
  private sse: EventSource | null = null;
  private ws: WebSocket | null = null;
  private handlers: ((event: SyncEvent) => void)[] = [];

  connect(projectId: string) {
    this.projectId = projectId;

    // SSE for server→client (low-frequency, broadcast)
    this.sse = new EventSource(`/api/sync/sse?project=${projectId}`);
    this.sse.onmessage = (e) => {
      const event = JSON.parse(e.data) as SyncEvent;
      this.broadcast(event);
    };

    // WebSocket for client→client (high-frequency, low-latency)
    this.ws = new WebSocket(`wss://api.editorlens.com/sync?project=${projectId}`);
    this.ws.onopen = () => {
      // Send initial presence
      this.send({ type: 'PRESENCE', payload: { userId: user.id } });
    };
    this.ws.onmessage = (e) => {
      const event = JSON.parse(e.data) as SyncEvent;
      this.broadcast(event);
    };
  }

  send(event: SyncEvent) {
    if (event.type === 'PRESENCE' || event.type === 'LOCK_ACQUIRED') {
      // Use WebSocket for latency-sensitive events
      this.ws?.send(JSON.stringify(event));
    } else {
      // Use SSE for state deltas (idempotent, reliable)
      this.sse?.send(JSON.stringify(event));
    }
  }

  onEvent(handler: (event: SyncEvent) => void) {
    this.handlers.push(handler);
    return () => this.handlers = this.handlers.filter(h => h !== handler);
  }

  private broadcast(event: SyncEvent) {
    this.handlers.forEach(h => h(event));
  }
}
```

